LOGO_PNG_BASE64 = """"""


def now():
    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")


def today():
    return datetime.now().strftime("%Y-%m-%d")


def hash_password(password: str, salt: str) -> str:
    return hashlib.sha256((salt + password).encode("utf-8")).hexdigest()


class DB:
    def __init__(self, path):
        self.path = path
        self.conn = sqlite3.connect(self.path)
        self.conn.row_factory = sqlite3.Row
        self.init_db()

    def init_db(self):
        cur = self.conn.cursor()
        cur.executescript("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            salt TEXT NOT NULL,
            role TEXT NOT NULL,
            active INTEGER NOT NULL DEFAULT 1,
            created_at TEXT NOT NULL
        );

        CREATE TABLE IF NOT EXISTS items (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            code TEXT UNIQUE NOT NULL,
            name TEXT NOT NULL,
            category TEXT,
            unit TEXT,
            min_qty REAL NOT NULL DEFAULT 0,
            location TEXT,
            notes TEXT,
            created_at TEXT NOT NULL
        );

        CREATE TABLE IF NOT EXISTS suppliers (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL,
            phone TEXT,
            email TEXT,
            notes TEXT,
            created_at TEXT NOT NULL
        );

        CREATE TABLE IF NOT EXISTS transactions (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            item_id INTEGER NOT NULL,
            tx_type TEXT NOT NULL,
            qty REAL NOT NULL,
            tx_date TEXT NOT NULL,
            ref TEXT,
            party TEXT,
            notes TEXT,
            created_by TEXT,
            created_at TEXT NOT NULL,
            FOREIGN KEY(item_id) REFERENCES items(id)
        );

        CREATE TABLE IF NOT EXISTS login_log (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT,
            success INTEGER NOT NULL,
            log_time TEXT NOT NULL
        );
        """)
        self.conn.commit()
        self.ensure_default_users()
        self.migrate_legacy_defaults()

    def ensure_default_users(self):
        cur = self.conn.cursor()
        count = cur.execute("SELECT COUNT(*) c FROM users").fetchone()["c"]
        if count == 0:
            for username, password, role in DEFAULT_USERS:
                salt = secrets.token_hex(8)
                cur.execute(
                    "INSERT INTO users (username,password_hash,salt,role,active,created_at) VALUES (?,?,?,?,1,?)",
                    (username, hash_password(password, salt), salt, role, now())
                )
            self.conn.commit()

    def migrate_legacy_defaults(self):
        cur = self.conn.cursor()
        changed = False
        for old_username, new_data in LEGACY_DEFAULTS.items():
            row = cur.execute("SELECT * FROM users WHERE username=?", (old_username,)).fetchone()
            if row:
                new_username, new_password, new_role = new_data
                exists = cur.execute("SELECT id FROM users WHERE username=?", (new_username,)).fetchone()
                if exists:
                    continue
                salt = secrets.token_hex(8)
                cur.execute(
                    "UPDATE users SET username=?, password_hash=?, salt=?, role=? WHERE id=?",
                    (new_username, hash_password(new_password, salt), salt, new_role, row["id"])
                )
                changed = True
        if changed:
            self.conn.commit()

    def verify_user(self, username, password):
        row = self.conn.execute("SELECT * FROM users WHERE username=?", (username,)).fetchone()
        success = False
        user = None
        if row and row["active"]:
            if hash_password(password, row["salt"]) == row["password_hash"]:
                success = True
                user = dict(row)
        self.conn.execute(
            "INSERT INTO login_log (username, success, log_time) VALUES (?,?,?)",
            (username, 1 if success else 0, now())
        )
        self.conn.commit()
        return user

    def fetchall(self, q, params=()):
        return [dict(r) for r in self.conn.execute(q, params).fetchall()]

    def fetchone(self, q, params=()):
        row = self.conn.execute(q, params).fetchone()
        return dict(row) if row else None

    def execute(self, q, params=()):
        cur = self.conn.execute(q, params)
        self.conn.commit()
        return cur


def load_config():
    if os.path.exists(CONFIG_PATH):
        try:
            with open(CONFIG_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            return {}
    return {}


def save_config(data):
    with open(CONFIG_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def apply_styles():
    style = ttk.Style()
    try:
        if "clam" in style.theme_names():
            style.theme_use("clam")
    except Exception:
        pass
    style.configure("Treeview", background="white", fieldbackground="white", foreground=COLORS["text"], rowheight=32, borderwidth=0, font=("Tahoma", 10))
    style.configure("Treeview.Heading", background=COLORS["accent_soft"], foreground=COLORS["primary"], relief="flat", font=("Tahoma", 10, "bold"))
    style.map("Treeview.Heading", background=[("active", COLORS["surface2"])])
    style.configure("TCombobox", fieldbackground="white", background="white", padding=6)
    style.configure("TCheckbutton", background="white", foreground=COLORS["text"], font=("Tahoma", 10))


class UiMixin:
    def get_logo_image(self):
        return tk.PhotoImage(data=LOGO_PNG_BASE64)

    def brand_logo(self, parent, bg="white"):
        holder = tk.Frame(parent, bg=bg, highlightbackground=COLORS["border"], highlightthickness=1)
        img = self.get_logo_image()
        lbl = tk.Label(holder, image=img, bg=bg, bd=0)
        lbl.image = img
        lbl.pack(padx=8, pady=8)
        holder.image = img
        return holder

    def section_title(self, parent, title, note=""):
        bar = tk.Frame(parent, bg=COLORS["bg"])
        bar.pack(fill="x", padx=16, pady=(16, 8))
        tk.Label(bar, text=title, bg=COLORS["bg"], fg=COLORS["text"], font=("Tahoma", 20, "bold")).pack(side="right")
        if note:
            tk.Label(bar, text=note, bg=COLORS["bg"], fg=COLORS["muted"], font=("Tahoma", 10)).pack(side="left")
        return bar

    def white_card(self, parent, title=None):
        frame = tk.Frame(parent, bg=COLORS["surface"], highlightbackground=COLORS["border"], highlightthickness=1)
        accent = tk.Frame(frame, bg=COLORS["accent"], height=5)
        accent.pack(fill="x", side="top")
        if title:
            hdr = tk.Frame(frame, bg=COLORS["surface"])
            hdr.pack(fill="x", padx=16, pady=(14, 6))
            tk.Label(hdr, text=title, bg=COLORS["surface"], fg=COLORS["text"], font=("Tahoma", 13, "bold")).pack(side="right")
        return frame

    def action_button(self, parent, text, command, bg=None, fg="white", width=None):
        return tk.Button(parent, text=text, command=command, bg=bg or COLORS["primary2"], fg=fg, activebackground=bg or COLORS["primary"], activeforeground=fg, font=("Tahoma", 10, "bold"), bd=0, cursor="hand2", width=width, relief="flat")


