    def show_transactions(self):
        self.clear_content()
        frame = tk.Frame(self.content, bg=COLORS["bg"])
        frame.pack(fill="both", expand=True)
        self.section_title(frame, "الحركات", "تسجيل الإضافة والصرف ومراجعة آخر العمليات")
        items = self.db.fetchall("SELECT id, code, name FROM items ORDER BY name")
        if not items:
            tk.Label(frame, text="أضف صنفًا أولًا قبل تسجيل الحركات", bg=COLORS["bg"], fg=COLORS["danger"], font=("Tahoma", 13, "bold")).pack(pady=40)
            return
        form = self.white_card(frame, "تسجيل حركة")
        form.pack(fill="x", padx=16)
        row = tk.Frame(form, bg=COLORS["surface"])
        row.pack(fill="x", padx=12, pady=10)
        item_map = {f"{r['name']} - {r['code']}": r['id'] for r in items}
        widgets = []
        defs = [("النوع", "combo_type"), ("الصنف", "combo_item"), ("الكمية", "qty"), ("التاريخ", "tx_date"), ("المرجع", "ref"), ("الجهة", "party")]
        for idx, (label, key) in enumerate(defs):
            col = tk.Frame(row, bg=COLORS["surface"])
            col.grid(row=0, column=idx, padx=5, sticky="nsew")
            tk.Label(col, text=label, bg=COLORS["surface"], font=("Tahoma", 10, "bold")).pack(anchor="e")
            widgets.append(col)
            row.grid_columnconfigure(idx, weight=1)
        tx_type = ttk.Combobox(widgets[0], values=["IN", "OUT"], state="readonly", justify="right")
        tx_type.set("IN"); tx_type.pack(fill="x", ipady=3)
        item_cb = ttk.Combobox(widgets[1], values=list(item_map.keys()), state="readonly", justify="right")
        item_cb.set(list(item_map.keys())[0]); item_cb.pack(fill="x", ipady=3)
        qty = tk.Entry(widgets[2], justify="right"); qty.pack(fill="x", ipady=6)
        tx_date = tk.Entry(widgets[3], justify="right"); tx_date.insert(0, today()); tx_date.pack(fill="x", ipady=6)
        ref = tk.Entry(widgets[4], justify="right"); ref.pack(fill="x", ipady=6)
        party = tk.Entry(widgets[5], justify="right"); party.pack(fill="x", ipady=6)
        notes_wrap = tk.Frame(form, bg=COLORS["surface"])
        notes_wrap.pack(fill="x", padx=12, pady=(0, 8))
        tk.Label(notes_wrap, text="ملاحظات", bg=COLORS["surface"], font=("Tahoma", 10, "bold")).pack(anchor="e")
        notes = tk.Entry(notes_wrap, justify="right")
        notes.pack(fill="x", ipady=6)

        def current_balance(item_id):
            r = self.db.fetchone("SELECT COALESCE(SUM(CASE WHEN tx_type='IN' THEN qty ELSE -qty END),0) c FROM transactions WHERE item_id=?", (item_id,))
            return float(r["c"])

        def save_tx():
            try:
                iid = item_map[item_cb.get()]
                q = float(qty.get().strip())
                if q <= 0:
                    raise ValueError("أدخل كمية صحيحة")
                if tx_type.get() == "OUT" and q > current_balance(iid):
                    raise ValueError("الكمية المصروفة أكبر من الرصيد")
                self.db.execute("""
                    INSERT INTO transactions (item_id,tx_type,qty,tx_date,ref,party,notes,created_by,created_at)
                    VALUES (?,?,?,?,?,?,?,?,?)
                """, (iid, tx_type.get(), q, tx_date.get().strip() or today(), ref.get().strip(), party.get().strip(), notes.get().strip(), self.user["username"], now()))
                messagebox.showinfo("نجاح", "تم حفظ الحركة")
                self.show_transactions()
            except Exception as e:
                messagebox.showerror("خطأ", str(e))

        self.action_button(form, "حفظ الحركة", save_tx).pack(anchor="w", padx=12, pady=(0, 12), ipadx=10, ipady=4)

        box = self.white_card(frame, "آخر الحركات")
        box.pack(fill="both", expand=True, padx=16, pady=16)
        tv = self.make_tree(box, [("date", "التاريخ", 100), ("type", "النوع", 80), ("item", "الصنف", 220), ("qty", "الكمية", 90), ("ref", "المرجع", 100), ("party", "الجهة", 130), ("by", "بواسطة", 110)])
        rows = self.db.fetchall("""
            SELECT t.*, i.name item_name FROM transactions t
            JOIN items i ON i.id=t.item_id
            ORDER BY t.id DESC LIMIT 250
        """)
        for r in rows:
            tv.insert("", "end", values=(r["tx_date"], "إضافة" if r["tx_type"] == "IN" else "صرف", r["item_name"], r["qty"], r["ref"], r["party"], r["created_by"]))

